// Transforme la reponse {items: [...], skipped: [...]} en N items individuels
// enrichis avec subject + html + text adaptes au type de relance.

const SUBJECTS = {
  j_minus_90: 'Renouvellement a prevoir',
  j_minus_30: 'Renouvellement urgent',
  j_minus_7: 'Renouvellement TRES urgent (J-7)',
  never_received: 'Document a transmettre',
};

const INTROS = {
  j_minus_90: (libelle, days) => `Ton document <strong>${libelle}</strong> arrive a expiration dans <strong>${days} jours</strong>.`,
  j_minus_30: (libelle, days) => `Ton document <strong>${libelle}</strong> expire dans <strong>${days} jours</strong>. Merci de le renouveler rapidement.`,
  j_minus_7: (libelle, days) => `<strong>Action urgente</strong> : ton document <strong>${libelle}</strong> expire dans <strong>${days} jours</strong>.`,
  never_received: (libelle) => `Nous n'avons pas encore recu ton document <strong>${libelle}</strong>. Merci de nous le transmettre.`,
};

const response = $input.first().json;
const items = response.items || [];

const out = items.map((item) => {
  const subject = `${SUBJECTS[item.type] || 'Document'} : ${item.document_type_libelle}`;
  const intro = (INTROS[item.type] || INTROS.never_received)(item.document_type_libelle, item.days_until_expiry);

  const html = `<!DOCTYPE html>
<html lang="fr"><head><meta charset="utf-8"></head>
<body style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 24px; color: #1A190F; background: #FAFAF7;">
  <h2 style="color: #2C6126; font-family: monospace;">Habilitation a renouveler - Montpellier Depannage</h2>
  <p>Bonjour ${item.driver_prenom},</p>
  <p>${intro}</p>
  <p>Pour mettre a jour ton dossier, merci d'envoyer le document via le lien securise ci-dessous :</p>
  <p style="text-align: center; margin: 32px 0;">
    <a href="${item.magic_link}" style="background: #2C6126; color: #ffffff; padding: 14px 28px; text-decoration: none; border-radius: 4px; display: inline-block; font-weight: bold;">Envoyer mon document</a>
  </p>
  <p style="color: #6B6B5E; font-size: 13px;">
    Lien valable 7 jours.<br>
    Si le bouton ne fonctionne pas, copie ce lien dans ton navigateur :<br>
    <span style="word-break: break-all; color: #2C6126;">${item.magic_link}</span>
  </p>
  <hr style="border: none; border-top: 1px solid #D3D1C7; margin: 32px 0;">
  <p style="color: #6B6B5E; font-size: 12px;">Email automatique - Montpellier Depannage</p>
</body></html>`;

  const text = `Bonjour ${item.driver_prenom},\n\n${item.document_type_libelle} : ${item.type === 'never_received' ? 'document non recu' : `expire dans ${item.days_until_expiry} jours`}.\n\nLien securise (valable 7 jours) :\n${item.magic_link}\n\n-- Montpellier Depannage`;

  return {
    json: {
      reminder_id: item.reminder_id,
      type: item.type,
      driver_email: item.driver_email,
      driver_prenom: item.driver_prenom,
      driver_nom: item.driver_nom,
      document_type_libelle: item.document_type_libelle,
      subject,
      html,
      text,
    },
  };
});

return out;

