// Collecte tous les reminder_id des envois reussis (Resend renvoie 200/201).
// On accede au reminder_id via l'item original (pas la reponse Resend).
const allItems = $input.all();
const reminder_ids = allItems
  .map((it) => it.json.reminder_id || it.json.id)
  .filter(Boolean);

return [{ json: { reminder_ids } }];
